INSERT INTO lessons (id, category_id, slug, title, summary, difficulty_level, estimated_minutes, sort_order, is_published)
VALUES ('40000000-0000-0000-0000-000000000001', 'c3000000-0000-0000-0000-000000000001', 'isa-basics',
  '命令セットアーキテクチャ（ISA）', 'ハードウェアとソフトウェアの契約。RISC vs CISC の設計哲学、レジスタ、アドレッシングモード。', 2, 30, 1, true);

INSERT INTO lesson_blocks (lesson_id, block_type, content, sort_order) VALUES
('40000000-0000-0000-0000-000000000001', 'markdown', '{"text": "# 命令セットアーキテクチャ（ISA）\n\n## ISA とは\n\nISA は**ハードウェアとソフトウェアの間のインターフェース（契約）**です。プログラマ（コンパイラ）から見えるプロセッサの抽象的な仕様であり、以下を定義します:\n\n- **命令の種類**: 算術、論理、メモリアクセス、制御フロー\n- **データ型**: 整数（8/16/32/64ビット）、浮動小数点、SIMD ベクタ\n- **レジスタ**: 数、幅、用途\n- **メモリモデル**: アドレッシングモード、エンディアン\n- **特権レベル**: ユーザーモード、カーネルモード\n\nISA が同じであれば、マイクロアーキテクチャ（内部実装）が異なっても同じプログラムが動作します。例: Intel Core と AMD Ryzen は異なるマイクロアーキテクチャだが、同じ x86-64 ISA を実装。"}', 0),

('40000000-0000-0000-0000-000000000001', 'markdown', '{"text": "## RISC vs CISC\n\n### CISC（Complex Instruction Set Computer）\n\n- 代表: **x86** (Intel/AMD)\n- 命令が複雑で多機能。1命令で「メモリから読み込み→演算→メモリに書き戻し」を実行可能\n- 可変長命令（1〜15バイト）\n- 命令数が多い（x86 は数千命令）\n- 目標: 命令数を減らしてプログラムサイズを小さくする（メモリが高価だった時代の設計）\n\n### RISC（Reduced Instruction Set Computer）\n\n- 代表: **ARM**, **RISC-V**, MIPS\n- 命令が単純で均一。Load/Store アーキテクチャ（メモリアクセスは load/store のみ、演算はレジスタ間のみ）\n- 固定長命令（通常32ビット）\n- 命令数が少ない（RISC-V の基本整数命令は約50個）\n- 目標: 各命令を1クロックで実行し、パイプラインを効率化\n\n### 現代の収束\n\n| | x86（CISC） | ARM（RISC） |\n|---|---|---|\n| 内部実装 | CISC命令をμops（RISC的な内部命令）に分解して実行 | 単純な命令をそのまま実行 |\n| パイプライン | 深い（14〜20段以上） | 比較的浅い（8〜13段） |\n| 消費電力 | 高い | **低い**（モバイル/サーバーで優位） |\n| 命令デコード | 複雑（可変長のパース） | 単純（固定長） |\n\n現代の x86 CPU は内部的に RISC 的に動作しており、RISC vs CISC の境界は曖昧になっています。Apple Silicon（M1〜M4）の成功は、RISC（ARM）が高性能領域でも CISC に対抗できることを示しました。"}', 1),

('40000000-0000-0000-0000-000000000001', 'markdown', '{"text": "## RISC-V: オープンな ISA\n\nRISC-V はカリフォルニア大学バークレー校で設計された**オープンソースの ISA**です。\n\n特徴:\n- ライセンスフリー（ARM のようなライセンス料不要）\n- モジュラー設計: 基本整数命令セット（RV32I/RV64I）に拡張を追加\n  - M: 乗算/除算\n  - A: アトミック操作\n  - F/D: 単精度/倍精度浮動小数点\n  - V: ベクタ演算\n- 学術研究とエッジコンピューティングで急速に普及中"}', 2),

('40000000-0000-0000-0000-000000000001', 'code', '{"language": "text", "code": "# RISC-V アセンブリ例: 2つの数の加算\n# x86 との対比で RISC の特徴を理解する\n\n# RISC-V (Load/Store アーキテクチャ)\n  lw   x5, 0(x10)     # メモリからレジスタにロード\n  lw   x6, 4(x10)     # メモリからレジスタにロード\n  add  x7, x5, x6     # レジスタ間で加算\n  sw   x7, 8(x10)     # レジスタからメモリにストア\n\n# x86 (CISC: メモリを直接オペランドに取れる)\n  mov  eax, [rdi]     # メモリからレジスタにロード\n  add  eax, [rdi+4]   # メモリの値を直接加算（1命令でload+add）\n  mov  [rdi+8], eax   # レジスタからメモリにストア\n\n# RISC-V: 4命令、各命令が単純で均一\n# x86:    3命令、add がメモリアクセスを含む複合命令", "runnable": false}', 3),

('40000000-0000-0000-0000-000000000001', 'markdown', '{"text": "## アドレッシングモード\n\n命令がオペランドの場所を指定する方法:\n\n| モード | 表記例 | 意味 | 用途 |\n|---|---|---|---|\n| レジスタ直接 | `add x5, x6, x7` | レジスタの値を直接使用 | 最高速 |\n| 即値 | `addi x5, x6, 10` | 定数値を命令に埋め込み | 定数の加算等 |\n| ベースオフセット | `lw x5, 8(x10)` | reg + offset のアドレス | 配列、構造体アクセス |\n| PC相対 | `beq x5, x6, label` | PC + offset | 分岐命令 |\n\nRISC-V はこの4種類に限定（単純性のため）。x86 はさらに複雑なモード（`[rax + rbx*4 + 8]`）をサポート。\n\n**学習のポイント**: ISA はハードウェア設計とコンパイラ設計の両方に影響する境界面。RISC の設計原則（単純・均一・固定長）がパイプライン効率に直結すること。現代の CISC が内部で RISC 的に動作する理由。"}', 4);

