INSERT INTO lessons (id, category_id, slug, title, summary, difficulty_level, estimated_minutes, sort_order, is_published)
VALUES ('40000000-0000-0000-0000-000000000002', 'c3000000-0000-0000-0000-000000000002', 'pipeline-basics',
  'パイプライン', '5段パイプライン、ハザード（データ/制御/構造）、フォワーディング、分岐予測。', 3, 30, 1, true);

INSERT INTO lesson_blocks (lesson_id, block_type, content, sort_order) VALUES
('40000000-0000-0000-0000-000000000002', 'markdown', '{"text": "# パイプライン\n\n## パイプラインの原理\n\nパイプラインは**命令の実行を複数のステージに分割し、異なる命令を同時に異なるステージで処理する**手法です。工場の流れ作業と同じ原理です。\n\n### 5段パイプライン（MIPS/RISC-V 古典モデル）\n\n| ステージ | 略称 | 処理内容 |\n|---|---|---|\n| 1. Instruction Fetch | **IF** | メモリから命令を読み込み、PC を更新 |\n| 2. Instruction Decode | **ID** | 命令を解読し、レジスタから値を読み出し |\n| 3. Execute | **EX** | ALU で演算またはアドレス計算 |\n| 4. Memory Access | **MEM** | load/store の場合にメモリアクセス |\n| 5. Write Back | **WB** | 結果をレジスタに書き戻し |\n\n### スループットの向上\n\n- パイプラインなし: 各命令が5サイクルで完了。n命令 = 5n サイクル\n- 5段パイプライン: 定常状態では**毎サイクル1命令完了**。n命令 ≈ n + 4 サイクル\n- スピードアップ（理想）: **ステージ数倍**（5倍）。ただし各ステージの時間が均等でないと最遅ステージがボトルネック\n\n$$\\text{Speedup}_{ideal} = \\frac{n \\times k}{n + k - 1} \\approx k \\quad (n \\gg k)$$\n\nk = ステージ数。命令数 n が十分大きければ、ステージ数倍のスピードアップ。"}', 0),

('40000000-0000-0000-0000-000000000002', 'markdown', '{"text": "## パイプラインハザード\n\nパイプラインの正常な流れを妨げる状況を**ハザード**と呼びます。\n\n### 1. データハザード\n\nある命令の結果を後続命令が必要とするが、まだ計算が完了していない。\n\n```\nadd x5, x1, x2   # x5 に書き込み（WBステージで完了）\nsub x6, x5, x3   # x5 を読み出し（IDステージ）← まだ書き込まれていない!\n```\n\n**対策**:\n- **フォワーディング（バイパス）**: EX/MEM ステージの出力を直接次の命令の入力に転送。多くのデータハザードを解消\n- **ストール（バブル）**: フォワーディングでも解決できない場合（例: load 直後の使用）、1サイクル待機\n\n```\nlw  x5, 0(x10)    # メモリからロード（MEMステージで値確定）\nadd x6, x5, x3    # x5 を使用（EXステージ）← フォワーディングでも1サイクル遅い\n# → コンパイラが命令を並べ替えて load-use ハザードを回避（命令スケジューリング）\n```\n\n### 2. 制御ハザード（分岐ハザード）\n\n分岐命令の結果が確定するまで、次に実行すべき命令が不明。\n\n```\nbeq x5, x6, label  # 分岐するか？（EXステージで判明）\nadd x7, x1, x2     # ← この命令を実行すべきか不明\nsub x8, x3, x4     # ← この命令も\n```\n\n**対策**:\n- **分岐予測**: 分岐の結果を予測して投機的に実行\n- **分岐遅延スロット**: 分岐命令の直後に常に実行される命令を配置（MIPS）\n\n### 3. 構造ハザード\n\n同じハードウェア資源を複数命令が同時に使用しようとする。\n\n例: IF と MEM が同時にメモリアクセス → 命令メモリとデータメモリを分離（ハーバードアーキテクチャ）で解決。"}', 1),

('40000000-0000-0000-0000-000000000002', 'markdown', '{"text": "## 分岐予測\n\n現代の CPU は深いパイプライン（14〜20段以上）を持つため、分岐の誤予測ペナルティが大きい（10〜20サイクルの無駄）。高精度な分岐予測が不可欠です。\n\n### 静的予測\n\n- 常に not-taken（分岐しない）と予測: ループの末尾では高い誤予測率\n- 後方分岐は taken、前方分岐は not-taken: ループに対して有効\n\n### 動的予測\n\n| 手法 | 状態 | 精度 |\n|---|---|---|\n| 1ビット予測器 | taken/not-taken | ループの最初と最後で必ず誤り |\n| 2ビット飽和カウンタ | 4状態（強taken/弱taken/弱not/強not） | 2回連続で外れないと予測を変更しない |\n| 相関予測器 | 直前の分岐結果のパターンに基づく | 条件が相関する場合に有効 |\n| Tournament予測器 | 複数の予測器の多数決 | 高精度（現代CPUで採用） |\n| TAGE | 分岐履歴の異なる長さを組み合わせ | 最高精度（>97%） |\n\n現代のプロセッサは **95〜99%** の予測精度を達成しています。\n\n**学習のポイント**: パイプラインのスピードアップが理想的にはステージ数倍であること。ハザードの3分類と各対策。フォワーディングがなぜデータハザードの多くを解消できるか。分岐予測の精度がパイプラインの深さに比例して重要になる理由。"}', 2);

