INSERT INTO lessons (id, category_id, slug, title, summary, difficulty_level, estimated_minutes, sort_order, is_published)
VALUES ('40000000-0000-0000-0000-000000000003', 'c3000000-0000-0000-0000-000000000003', 'cache-basics',
  'メモリ階層とキャッシュ', '局所性の原理、ダイレクトマップ/セットアソシアティブ/フルアソシアティブ、ライトポリシー。', 3, 35, 1, true);

INSERT INTO lesson_blocks (lesson_id, block_type, content, sort_order) VALUES
('40000000-0000-0000-0000-000000000003', 'markdown', '{"text": "# メモリ階層とキャッシュ\n\n## メモリ階層\n\nプロセッサの速度とメモリの速度の差（**メモリウォール**）は年々拡大しています。この問題を階層的なメモリ構造で緩和します。\n\n| レベル | 容量 | アクセス時間 | 帯域幅 |\n|---|---|---|---|\n| レジスタ | 数KB | < 1ns (0.5 サイクル) | — |\n| L1キャッシュ | 32〜64KB | 1〜2ns (3〜5 サイクル) | 数百GB/s |\n| L2キャッシュ | 256KB〜1MB | 3〜10ns (10〜20 サイクル) | 数十GB/s |\n| L3キャッシュ | 数MB〜数十MB | 10〜30ns (30〜70 サイクル) | 数十GB/s |\n| DRAM (メインメモリ) | 数GB〜数百GB | 50〜100ns (100〜300 サイクル) | 数十GB/s |\n| SSD | 数百GB〜TB | 10〜100μs | 数GB/s |\n| HDD | TB | 5〜10ms | 数百MB/s |\n\nL1 と DRAM の速度差は **約100倍**。キャッシュがなければ CPU は大半の時間をメモリ待ちに費やします。\n\n## 局所性の原理（Principle of Locality）\n\nキャッシュが有効な理由は、プログラムのメモリアクセスパターンに**局所性**があるからです:\n\n- **時間的局所性**: 一度アクセスしたデータは近い将来再びアクセスされやすい（ループ変数、関数の戻り先）\n- **空間的局所性**: あるアドレスにアクセスすると、近傍のアドレスも近い将来アクセスされやすい（配列の連続アクセス、命令の逐次実行）"}', 0),

('40000000-0000-0000-0000-000000000003', 'markdown', '{"text": "## キャッシュの構成\n\nキャッシュの基本パラメータ:\n- **ブロックサイズ（ラインサイズ）**: 一度に転送する単位（通常64バイト）\n- **キャッシュサイズ**: 全データの容量\n- **連想度（Associativity）**: 1ブロックが配置できる場所の数\n\n### アドレスの分解\n\nアドレスを3つのフィールドに分割:\n\n```\n| タグ (tag) | インデックス (index) | オフセット (offset) |\n```\n\n- **オフセット**: ブロック内の位置（log₂(ブロックサイズ) ビット）\n- **インデックス**: キャッシュのセット（行）を選択\n- **タグ**: そのセット内のどのブロックかを識別\n\n### マッピング方式\n\n| 方式 | 連想度 | 配置先 | ヒット率 | ハードウェアコスト |\n|---|---|---|---|---|\n| ダイレクトマップ | 1 | 1箇所のみ | 低い（コンフリクトミス多い） | 最小 |\n| N-way セットアソシアティブ | N | N箇所 | 中〜高 | 中 |\n| フルアソシアティブ | 全ライン | どこでも可 | 最高 | 最大（比較器が多い） |\n\n実用上は **8-way セットアソシアティブ**が最も一般的（ヒット率とハードウェアコストのバランス）。\n\n### 具体例: 32KB, 8-way, 64バイトブロックの L1 キャッシュ\n\n- ブロック数: 32KB / 64B = 512\n- セット数: 512 / 8 = 64\n- オフセット: log₂(64) = 6ビット\n- インデックス: log₂(64) = 6ビット\n- タグ: 残りのビット（64ビットアドレスなら 52ビット）"}', 1),

('40000000-0000-0000-0000-000000000003', 'markdown', '{"text": "## キャッシュミスの分類（3C モデル）\n\n| ミスの種類 | 原因 | 対策 |\n|---|---|---|\n| **Compulsory（初期）** | 初めてアクセスするブロック | プリフェッチ |\n| **Capacity（容量）** | キャッシュに収まらない | キャッシュサイズ拡大 |\n| **Conflict（衝突）** | 同じセットにマップされるブロックが多い | 連想度を上げる |\n\n## ライトポリシー\n\n書き込み時のキャッシュとメモリの整合性の管理:\n\n| ポリシー | 動作 | 利点 | 欠点 |\n|---|---|---|---|\n| **Write-through** | キャッシュとメモリに同時書き込み | メモリが常に最新 | 書き込み帯域幅大（ライトバッファで緩和） |\n| **Write-back** | キャッシュにのみ書き込み、追い出し時にメモリに反映 | 書き込み帯域幅小 | 一貫性管理が複雑（ダーティビット） |\n\nライトミス時:\n- **Write-allocate**: ブロックをキャッシュに読み込んでから書き込み（Write-back と組み合わせ）\n- **No-write-allocate**: メモリに直接書き込み（Write-through と組み合わせ）\n\n## プログラマが意識すべきこと\n\n```c\n// 悪い例: 列方向アクセス（空間的局所性が低い）\nfor (int j = 0; j < N; j++)\n    for (int i = 0; i < N; i++)\n        sum += A[i][j];  // キャッシュミス多発\n\n// 良い例: 行方向アクセス（空間的局所性が高い）\nfor (int i = 0; i < N; i++)\n    for (int j = 0; j < N; j++)\n        sum += A[i][j];  // 連続メモリアクセス → キャッシュヒット\n```\n\nC/C++ の2次元配列は行優先（Row-major）。行方向のアクセスは連続メモリアクセスとなり、キャッシュラインを有効に利用できます。N=1000 の場合、列方向は行方向の **10〜100倍遅い**ことがあります。\n\n**学習のポイント**: メモリウォール問題と階層構造による緩和。局所性の2種類を具体例で理解。アドレスのタグ/インデックス/オフセットへの分解。3Cモデルによるミスの分類と対策。プログラムのメモリアクセスパターンがキャッシュ効率に直結すること。"}', 2);

