-- Quiz: ISA
INSERT INTO quizzes (id, category_id, title, difficulty_level, is_published)
VALUES ('d3000000-0000-0000-0000-000000000001', 'c3000000-0000-0000-0000-000000000001',
  '命令セットアーキテクチャクイズ', 2, true);

INSERT INTO questions (id, quiz_id, question_type, prompt, options, correct_answer, explanation, sort_order, points) VALUES
('f2000000-0000-0000-0000-000000000001', 'd3000000-0000-0000-0000-000000000001',
  'multiple_choice', 'RISC アーキテクチャの特徴として正しいものは？',
  '[{"id":"a","text":"可変長命令"},{"id":"b","text":"1命令でメモリアクセスと演算を同時実行"},{"id":"c","text":"固定長命令と Load/Store アーキテクチャ"},{"id":"d","text":"命令数が数千種類"}]',
  '{"answer":"c"}',
  'RISC は固定長命令と Load/Store アーキテクチャ（メモリアクセスは load/store 命令のみ、演算はレジスタ間のみ）が特徴です。',
  1, 10),
('f2000000-0000-0000-0000-000000000002', 'd3000000-0000-0000-0000-000000000001',
  'multiple_choice', 'ISA の役割として最も適切なのは？',
  '[{"id":"a","text":"CPU の内部配線の設計図"},{"id":"b","text":"ハードウェアとソフトウェアの間のインターフェース"},{"id":"c","text":"OS のシステムコール仕様"},{"id":"d","text":"コンパイラの最適化アルゴリズム"}]',
  '{"answer":"b"}',
  'ISA はハードウェアとソフトウェアの契約（インターフェース）です。同じ ISA であれば異なるマイクロアーキテクチャでも同じプログラムが動作します。',
  2, 10);

