INSERT INTO questions (id, quiz_id, question_type, prompt, options, correct_answer, explanation, sort_order, points) VALUES
('f2000000-0000-0000-0000-000000000003', 'd3000000-0000-0000-0000-000000000002',
  'multiple_choice', '5段パイプラインの理想的なスピードアップは？',
  '[{"id":"a","text":"2倍"},{"id":"b","text":"5倍"},{"id":"c","text":"10倍"},{"id":"d","text":"25倍"}]',
  '{"answer":"b"}',
  '理想的にはステージ数倍のスピードアップが得られます。5段パイプラインなら最大5倍です。',
  1, 10),
('f2000000-0000-0000-0000-000000000004', 'd3000000-0000-0000-0000-000000000002',
  'multiple_choice', 'データハザードの主な対策として使われる手法は？',
  '[{"id":"a","text":"分岐予測"},{"id":"b","text":"フォワーディング（バイパス）"},{"id":"c","text":"キャッシュの増設"},{"id":"d","text":"クロック周波数の低下"}]',
  '{"answer":"b"}',
  'フォワーディング（バイパス）は、演算結果を後続命令に直接転送することでデータハザードによるストールを回避します。',
  2, 10),
('f2000000-0000-0000-0000-000000000005', 'd3000000-0000-0000-0000-000000000002',
  'fill_in_blank', '現代のCPUの分岐予測精度は___〜99%に達する。',
  NULL, '{"answers":["95","95%"]}',
  '現代のプロセッサは TAGE などの高度な予測器を用いて95〜99%の分岐予測精度を達成しています。',
  3, 10);

