INSERT INTO questions (id, quiz_id, question_type, prompt, options, correct_answer, explanation, sort_order, points) VALUES
('f2000000-0000-0000-0000-000000000006', 'd3000000-0000-0000-0000-000000000003',
  'multiple_choice', 'キャッシュが有効に機能する根拠となる原理は？',
  '[{"id":"a","text":"ムーアの法則"},{"id":"b","text":"アムダールの法則"},{"id":"c","text":"局所性の原理"},{"id":"d","text":"ベルヌーイの定理"}]',
  '{"answer":"c"}',
  '局所性の原理（時間的局所性と空間的局所性）により、プログラムのメモリアクセスに規則性があるためキャッシュが有効です。',
  1, 10),
('f2000000-0000-0000-0000-000000000007', 'd3000000-0000-0000-0000-000000000003',
  'multiple_choice', 'キャッシュミスの3C分類に含まれないものは？',
  '[{"id":"a","text":"Compulsory（初期ミス）"},{"id":"b","text":"Capacity（容量ミス）"},{"id":"c","text":"Coherence（整合性ミス）"},{"id":"d","text":"Conflict（衝突ミス）"}]',
  '{"answer":"c"}',
  '3Cモデルは Compulsory（初期）、Capacity（容量）、Conflict（衝突）の3種類です。Coherence ミスはマルチプロセッサ環境で追加される4番目のCです。',
  2, 10),
('f2000000-0000-0000-0000-000000000008', 'd3000000-0000-0000-0000-000000000003',
  'true_false', 'C言語の2次元配列で、列方向のアクセスは行方向のアクセスよりキャッシュ効率が悪い。',
  '[{"id":"true","text":"正しい"},{"id":"false","text":"誤り"}]',
  '{"answer":true}',
  'C の2次元配列は行優先（Row-major）でメモリに配置されるため、行方向のアクセスは連続メモリアクセスとなりキャッシュヒット率が高く、列方向は飛び飛びのアクセスとなりキャッシュミスが多発します。',
  3, 10);

