INSERT INTO questions (id, quiz_id, question_type, prompt, options, correct_answer, explanation, sort_order, points) VALUES
('f2000000-0000-0000-0000-000000000009', 'd3000000-0000-0000-0000-000000000004',
  'multiple_choice', 'プログラムの90%が並列化可能な場合、アムダールの法則による最大スピードアップは？',
  '[{"id":"a","text":"5倍"},{"id":"b","text":"10倍"},{"id":"c","text":"90倍"},{"id":"d","text":"無限大"}]',
  '{"answer":"b"}',
  'Speedup = 1/(1-P) = 1/0.1 = 10倍。プロセッサ数を無限に増やしても、10%の逐次部分が上限を決めます。',
  1, 10),
('f2000000-0000-0000-0000-000000000010', 'd3000000-0000-0000-0000-000000000004',
  'multiple_choice', 'MESI プロトコルで、あるコアがShared状態のキャッシュラインに書き込むとどうなる？',
  '[{"id":"a","text":"何も起きない"},{"id":"b","text":"他コアの該当ラインがInvalidになる"},{"id":"c","text":"全キャッシュがフラッシュされる"},{"id":"d","text":"メモリに即座に書き込まれる"}]',
  '{"answer":"b"}',
  'あるコアがSharedラインに書き込むと、そのラインはModifiedに遷移し、他コアの該当ラインはInvalidateされます。これによりキャッシュ間の一貫性が保たれます。',
  2, 10);
